<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;use App\Services\InspectionAttachmentService;use App\Services\InspectionPacketService;
final class InspectionController{
 public function start(int $jobId):void{Auth::requireLogin();verify_csrf();$templateId=(int)($_POST['inspection_template_id']??0);$pdo=Database::connection();$q=$pdo->prepare("SELECT id FROM inspection_templates WHERE id=? AND entity_type='job' AND active=1");$q->execute([$templateId]);if(!$q->fetchColumn()){flash('danger','Invalid inspection template.');redirect('/portal/jobs/'.$jobId);} $pdo->prepare("INSERT INTO inspections(inspection_template_id,entity_type,entity_id,status) VALUES(?,'job',?,'draft')")->execute([$templateId,$jobId]);$id=(int)$pdo->lastInsertId();AuditService::log('inspection.started','inspection',$id,['job_id'=>$jobId]);redirect('/portal/inspections/'.$id);}
 public function show(int $id):void{Auth::requireLogin();$pdo=Database::connection();$q=$pdo->prepare("SELECT i.*,t.name template_name,t.description,j.job_number,j.assigned_user_id,c.display_name FROM inspections i JOIN inspection_templates t ON t.id=i.inspection_template_id LEFT JOIN jobs j ON i.entity_type='job' AND j.id=i.entity_id LEFT JOIN customers c ON c.id=j.customer_id WHERE i.id=?");$q->execute([$id]);$inspection=$q->fetch();if(!$inspection){http_response_code(404);exit('Inspection not found');}if(Auth::role()==='technician'&&(int)$inspection['assigned_user_id']!==(int)Auth::id()){http_response_code(403);exit('Access denied');}$items=$pdo->prepare('SELECT ti.*,r.response_text,r.response_json FROM inspection_template_items ti LEFT JOIN inspection_responses r ON r.inspection_template_item_id=ti.id AND r.inspection_id=? WHERE ti.inspection_template_id=? ORDER BY ti.sort_order,ti.id');$items->execute([$id,$inspection['inspection_template_id']]);$rows=$items->fetchAll();foreach($rows as &$row)$row['options']=json_decode($row['options_json']??'[]',true)?:[];$a=$pdo->prepare('SELECT * FROM inspection_attachments WHERE inspection_id=? ORDER BY created_at DESC');$a->execute([$id]);View::render('portal/inspections/show',['title'=>$inspection['template_name'],'inspection'=>$inspection,'items'=>$rows,'attachments'=>$a->fetchAll()],'portal');}
 public function save(int $id):void{Auth::requireLogin();verify_csrf();$pdo=Database::connection();$q=$pdo->prepare('SELECT i.*,j.assigned_user_id FROM inspections i LEFT JOIN jobs j ON i.entity_type="job" AND j.id=i.entity_id WHERE i.id=?');$q->execute([$id]);$inspection=$q->fetch();if(!$inspection){http_response_code(404);exit('Inspection not found');}if(Auth::role()==='technician'&&(int)$inspection['assigned_user_id']!==(int)Auth::id()){http_response_code(403);exit('Access denied');}$items=$pdo->prepare('SELECT * FROM inspection_template_items WHERE inspection_template_id=? ORDER BY sort_order,id');$items->execute([$inspection['inspection_template_id']]);$up=$pdo->prepare('INSERT INTO inspection_responses(inspection_id,inspection_template_item_id,response_text,response_json) VALUES(?,?,?,?) ON DUPLICATE KEY UPDATE response_text=VALUES(response_text),response_json=VALUES(response_json),updated_at=NOW()');foreach($items->fetchAll() as $item){$key='item_'.$item['id'];$value=$item['field_type']==='checkbox'?(isset($_POST[$key])?'1':'0'):trim((string)($_POST[$key]??''));if($item['required']&&$value===''){flash('danger',$item['label'].' is required.');redirect('/portal/inspections/'.$id);} $up->execute([$id,$item['id'],$value,null]);}$complete=isset($_POST['complete']);$pdo->prepare('UPDATE inspections SET status=?,completed_by=?,completed_at=? ,notes=? WHERE id=?')->execute([$complete?'completed':'draft',$complete?Auth::id():null,$complete?date('Y-m-d H:i:s'):null,trim($_POST['notes']??''),$id]);AuditService::log($complete?'inspection.completed':'inspection.saved','inspection',$id);flash('success',$complete?'Inspection completed.':'Inspection saved.');redirect('/portal/jobs/'.$inspection['entity_id']);}


 public function pdf(int $id):void{Auth::requireLogin();$packet=(new InspectionPacketService())->render($id);header('Content-Type: application/pdf');header('Content-Disposition: attachment; filename="'.$packet['filename'].'"');header('Content-Length: '.strlen($packet['bytes']));echo $packet['bytes'];exit;}
 public function uploadAttachment(int $id):void{Auth::requireLogin();verify_csrf();if(empty($_FILES['attachment']['tmp_name'])||$_FILES['attachment']['error']!==UPLOAD_ERR_OK){flash('danger','Choose a valid image.');redirect('/portal/inspections/'.$id);} $mime=(new \finfo(FILEINFO_MIME_TYPE))->file($_FILES['attachment']['tmp_name']);$ext=match($mime){'image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp',default=>''};if(!$ext||$_FILES['attachment']['size']>10*1024*1024){flash('danger','Use a JPG, PNG, or WebP image under 10 MB.');redirect('/portal/inspections/'.$id);} $name=bin2hex(random_bytes(12)).'.'.$ext;$dir=upload_dir('inspections/'.$id);move_uploaded_file($_FILES['attachment']['tmp_name'],$dir.'/'.$name);$relative='inspections/'.$id.'/'.$name;$policy=InspectionAttachmentService::policy('photo');$thumb=!empty($policy['create_thumbnail'])?InspectionAttachmentService::thumbnail($dir.'/'.$name,$relative,(int)$policy['thumbnail_width']):null;$expires=!empty($policy['retain_days'])?date('Y-m-d H:i:s',strtotime('+'.(int)$policy['retain_days'].' days')):null;Database::connection()->prepare("INSERT INTO inspection_attachments(inspection_id,inspection_template_item_id,attachment_type,filename,storage_path,thumbnail_path,mime_type,caption,expires_at,uploaded_by) VALUES(?,?,'photo',?,?,?,?,?,?,?,?)")->execute([$id,($_POST['item_id']??'')!==''?(int)$_POST['item_id']:null,$_FILES['attachment']['name'],$relative,$thumb,$mime,trim($_POST['caption']??''),$expires,Auth::id()]);AuditService::log('inspection.photo_uploaded','inspection',$id);flash('success','Inspection photo uploaded.');redirect('/portal/inspections/'.$id);}
 public function saveSignature(int $id):void{Auth::requireLogin();verify_csrf();$data=(string)($_POST['signature_data']??'');if(!preg_match('#^data:image/png;base64,(.+)$#',$data,$m)){flash('danger','Signature was empty or invalid.');redirect('/portal/inspections/'.$id);} $binary=base64_decode($m[1],true);if($binary===false||strlen($binary)>3*1024*1024){flash('danger','Signature could not be saved.');redirect('/portal/inspections/'.$id);} $name=bin2hex(random_bytes(12)).'.png';$dir=upload_dir('inspections/'.$id);file_put_contents($dir.'/'.$name,$binary);$policy=InspectionAttachmentService::policy('signature');$expires=!empty($policy['retain_days'])?date('Y-m-d H:i:s',strtotime('+'.(int)$policy['retain_days'].' days')):null;Database::connection()->prepare("INSERT INTO inspection_attachments(inspection_id,inspection_template_item_id,attachment_type,filename,storage_path,mime_type,caption,expires_at,uploaded_by) VALUES(?,?,'signature',? ,?,'image/png',?,?,?)")->execute([$id,($_POST['item_id']??'')!==''?(int)$_POST['item_id']:null,$name,'inspections/'.$id.'/'.$name,trim($_POST['caption']??'Inspection signature'),$expires,Auth::id()]);AuditService::log('inspection.signature_saved','inspection',$id);flash('success','Signature saved.');redirect('/portal/inspections/'.$id);}
}
